module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const unit = esc(args.unit || '');
const steps = [];
sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).forEach((l) => {
  const i = l.indexOf('|');
  if (i < 0) return;
  const raw = l.slice(i + 1).trim();
  const v = parseFloat(raw);
  if (Number.isFinite(v)) steps.push({ label: l.slice(0, i).trim(), v, delta: /^[+\-]/.test(raw) });
});
if (!steps.length) return `<div>(waterfall: lines like "Label | +30")</div>`;
// running levels
const bars = [];
let cum = 0;
steps.forEach((s, i) => {
  const from = i === 0 && !s.delta ? 0 : cum;
  cum = i === 0 && !s.delta ? s.v : cum + s.v;
  bars.push({ label: s.label, lo: Math.min(from, cum), hi: Math.max(from, cum), v: s.v, kind: i === 0 && !s.delta ? 'base' : (s.v >= 0 ? 'up' : 'down') });
});
const totalLabel = String(args.total ?? 'Total').trim();
if (totalLabel && totalLabel.toLowerCase() !== 'none') {
  bars.push({ label: totalLabel, lo: Math.min(0, cum), hi: Math.max(0, cum), v: cum, kind: 'base' });
}
const lo = Math.min(0, ...bars.map((b) => b.lo)), hi = Math.max(...bars.map((b) => b.hi), lo + 1);
const span = hi - lo;
const pct = (v) => ((v - lo) / span) * 100;
const fv = (v) => { const r = +v.toFixed(2); return (r > 0 && bars.length ? '' : '') + String(r); };
const hRaw = parseInt(args.height, 10);
const height = Number.isFinite(hRaw) && hRaw > 0 ? hRaw : 210;
const showValues = String(args.showvalues) !== 'false';
const upColor = (args.upcolor || '#22c55e').trim() || '#22c55e';
const downColor = (args.downcolor || '#ef4444').trim() || '#ef4444';
const wrapCls = 'mdp-mod-waterfall' + (showValues ? '' : ' mdp-wf-novalues');
let html = `\n\n<div class="${wrapCls}" style="--wf-h:${height}px; --wf-up:${upColor}; --wf-down:${downColor};"><div class="mdp-wf-plot">`;
bars.forEach((b) => {
  html += `<div class="mdp-wf-col"><div class="mdp-wf-bar mdp-wf-${b.kind}" style="bottom:${pct(b.lo).toFixed(1)}%; height:${Math.max(0.8, pct(b.hi) - pct(b.lo)).toFixed(1)}%;">` +
    `<span class="mdp-wf-val">${b.kind === 'up' ? '+' : ''}${fv(b.v)}${unit}</span></div>` +
    `<div class="mdp-wf-lbl">${esc(b.label)}</div></div>`;
});
html += `</div></div>\n\n`;
return html;
